Sanitize input before processing:
import "html"

func sanitizeName(name string) string {
  // Trim whitespace
  name = strings.TrimSpace(name)
  // Escape HTML entities
  name = html.EscapeString(name)
  // Remove control characters
  name = strings.Map(func(r rune) rune {
    if unicode.IsControl(r) && r != '\n' && r != '\t' {
      return -1
    }
    return r
  }, name)
  return name
}

req.Name = sanitizeName(req.Name)

Implement rate limiting:
type RateLimiter struct {
  tokens   chan struct{}
  interval time.Duration
}

func NewRateLimiter(maxPerSecond int) *RateLimiter {
  rl := &RateLimiter{
    tokens:   make(chan struct{}, maxPerSecond),
    interval: time.Second / time.Duration(maxPerSecond),
  }
  go func() {
    ticker := time.NewTicker(rl.interval)
    defer ticker.Stop()
    for range ticker.C {
      select {
      case rl.tokens <- struct{}{}:
      default:
      }
    }
  }()
  return rl
}

// In handler:
select {
case <-rateLimiter.tokens:
  // Process message
default:
  conn.WriteJSON(map[string]interface{}{
    "type": "error",
    "message": "Rate limit exceeded",
  })
}

Enhance logging with correlation IDs:
import "github.com/google/uuid"

func Logger() gin.HandlerFunc {
  return func(c *gin.Context) {
    // Generate or extract correlation ID
    correlationID := c.GetHeader("X-Correlation-ID")
    if correlationID == "" {
      correlationID = uuid.New().String()
    }
    c.Header("X-Correlation-ID", correlationID)

    // Add to context for downstream use
    ctx := context.WithValue(c.Request.Context(), "correlation_id", correlationID)
    c.Request = c.Request.WithContext(ctx)

    start := time.Now()
    c.Next()
    latency := time.Since(start)

    // Log with correlation ID
    logger := zap.L().With(zap.String("correlation_id", correlationID))
    if c.Writer.Status() >= 500 {
      logger.Error("请求失败",
        zap.String("method", c.Request.Method),
        zap.String("path", c.Request.URL.Path),
        zap.Int("status", c.Writer.Status()),
        zap.Duration("latency", latency),
      )
    } else {
      logger.Info("请求日志",
        zap.String("method", c.Request.Method),
        zap.String("path", c.Request.URL.Path),
        zap.Int("status", c.Writer.Status()),
        zap.Duration("latency", latency),
      )
    }
  }
}

